<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\{Task,TaskApproval};use App\Support\CurrentWorkspace;use Illuminate\Http\Request;
class TaskApprovalController extends Controller{use Concerns;public function request(Request $r,Task $task,CurrentWorkspace $cw){$this->requirePerm('tenant.tasks.complete');if($task->proof_required && !$task->proofs()->whereIn('status',['submitted','approved'])->exists())return back()->withErrors(['proof'=>'Proof is required before completion request.']);if(!$task->approval_required){$task->update(['status'=>'completed','completed_at'=>now(),'completed_by'=>$r->user()->id]);$this->logTask($task,'completed',[],['status'=>'completed'],'Task completed');return back();}$task->update(['status'=>'review','approval_status'=>'pending']);$approval=TaskApproval::create(['workspace_id'=>$cw->required()->id,'task_id'=>$task->id,'requested_by'=>$r->user()->id,'status'=>'pending','requested_at'=>now()]);$this->logTask($task,'approval_requested',[],['approval_id'=>$approval->id],'Task completion approval requested');return back();}public function index(){return view('tenant.approvals.index',['approvals'=>TaskApproval::with('task','requester')->where('status','pending')->latest()->paginate(15)]);}public function approve(Request $r,TaskApproval $approval){$this->requirePerm('tenant.tasks.approve');$approval->update(['status'=>'approved','approver_id'=>$r->user()->id,'reviewed_at'=>now(),'comment'=>$r->input('comment')]);$approval->task->update(['status'=>'completed','completed_at'=>now(),'completed_by'=>$approval->requested_by,'approval_status'=>'approved']);$this->logTask($approval->task,'approval_approved',[],['approval_id'=>$approval->id],'Task approved and completed');return back();}public function reject(Request $r,TaskApproval $approval){$this->requirePerm('tenant.tasks.approve');$d=$r->validate(['rejection_reason'=>'required|string']);$approval->update($d+['status'=>'rejected','approver_id'=>$r->user()->id,'reviewed_at'=>now()]);$approval->task->update(['status'=>'reopened','approval_status'=>'rejected']);$this->logTask($approval->task,'approval_rejected',[],['approval_id'=>$approval->id],'Task rejected and reopened');return back();}}
